"use strict";(globalThis.webpackChunkflarum_docs=globalThis.webpackChunkflarum_docs||[]).push([[8083],{8890(e){e.exports=JSON.parse('{"pluginId":"default","version":"1.x","label":"1.x","banner":null,"badge":true,"noIndex":false,"className":"docs-version-1.x","isLast":true,"docsSidebars":{"guideSidebar":[{"type":"category","label":"Introduction","collapsible":false,"className":"menu__intro-category","items":[{"type":"link","label":"README","href":"/de/","docId":"README"},{"type":"link","label":"Verhaltenskodex","href":"/de/code-of-conduct","docId":"code-of-conduct"},{"type":"link","label":"Versionshinweise","href":"/de/releases","docId":"releases"},{"type":"link","label":"Fehler melden","href":"/de/bugs","docId":"bugs"},{"type":"link","label":"FAQ","href":"/de/faq","docId":"faq"}],"collapsed":false},{"type":"category","label":"Contribute","collapsible":false,"className":"menu__contribute-category","items":[{"type":"link","label":"Hilf Flarum aufzubauen","href":"/de/contributing","docId":"contributing"},{"type":"link","label":"Dokumente und \xdcbersetzung","href":"/de/contributing-docs-translations","docId":"contributing-docs-translations"},{"type":"link","label":"Other Ways to Help","href":"/#help-the-flarum-project"}],"collapsed":false},{"type":"category","label":"Setting Up","collapsible":false,"className":"menu__install-category","items":[{"type":"link","label":"Composer","href":"/de/composer","docId":"composer"},{"type":"link","label":"Installation","href":"/de/install","docId":"install"},{"type":"link","label":"Updating","href":"/de/update","docId":"update"},{"type":"link","label":"Problembehandlung","href":"/de/troubleshoot","docId":"troubleshoot"}],"collapsed":false},{"type":"category","label":"Management","collapsible":false,"className":"menu__manage-category","items":[{"type":"link","label":"Admin-Dashboard","href":"/de/admin","docId":"admin"},{"type":"link","label":"Konfigurationsdatei","href":"/de/config","docId":"config"},{"type":"link","label":"Erweiterungen","href":"/de/extensions","docId":"extensions"},{"type":"link","label":"Sprachen","href":"/de/languages","docId":"languages"},{"type":"link","label":"Design","href":"/de/themes","docId":"themes"},{"type":"link","label":"E-Mail-Konfiguration","href":"/de/mail","docId":"mail"},{"type":"link","label":"Scheduler","href":"/de/scheduler","docId":"scheduler"},{"type":"link","label":"Konsole","href":"/de/console","docId":"console"}],"collapsed":false},{"type":"category","label":"Advanced","collapsible":false,"className":"menu__advanced-category","items":[{"type":"link","label":"Consuming the REST API","href":"/de/rest-api","docId":"rest-api"},{"type":"link","label":"Lokale Extender","href":"/de/extenders","docId":"extenders"}],"collapsed":false}],"extendSidebar":[{"type":"category","label":"Main Concepts","collapsible":false,"className":"menu__intro-category","items":[{"type":"link","label":"README","href":"/de/extend/","docId":"extend/README"},{"type":"link","label":"Getting Started","href":"/de/extend/start","docId":"extend/start"},{"type":"link","label":"Frontend Development","href":"/de/extend/frontend","docId":"extend/frontend"},{"type":"link","label":"Routes and Content","href":"/de/extend/routes","docId":"extend/routes"},{"type":"link","label":"Models and Migrations","href":"/de/extend/models","docId":"extend/models"},{"type":"link","label":"API and Data Flow","href":"/de/extend/api","docId":"extend/api"},{"type":"link","label":"Distribution","href":"/de/extend/distribution","docId":"extend/distribution"},{"type":"link","label":"Flarum CLI","href":"/de/extend/cli","docId":"extend/cli"}],"collapsed":false},{"type":"category","label":"Reference Guides","collapsible":false,"className":"menu__update-category","items":[{"type":"link","label":"Admin-Dashboard","href":"/de/extend/admin","docId":"extend/admin"},{"type":"link","label":"Backend Events","href":"/de/extend/backend-events","docId":"extend/backend-events"},{"type":"link","label":"Authorization","href":"/de/extend/authorization","docId":"extend/authorization"},{"type":"link","label":"Frontend Pages and Resolvers","href":"/de/extend/frontend-pages","docId":"extend/frontend-pages"},{"type":"link","label":"Interactive Components","href":"/de/extend/interactive-components","docId":"extend/interactive-components"},{"type":"link","label":"Internationalization","href":"/de/extend/i18n","docId":"extend/i18n"},{"type":"link","label":"Translating Flarum","href":"/de/extend/language-packs","docId":"extend/language-packs"},{"type":"link","label":"Forms and Requests","href":"/de/extend/forms","docId":"extend/forms"},{"type":"link","label":"Groups and Permissions","href":"/de/extend/permissions","docId":"extend/permissions"},{"type":"link","label":"Settings","href":"/de/extend/settings","docId":"extend/settings"},{"type":"link","label":"Static Code Analysis","href":"/de/extend/static-code-analysis","docId":"extend/static-code-analysis"},{"type":"link","label":"Testing","href":"/de/extend/testing","docId":"extend/testing"},{"type":"link","label":"Themes","href":"/de/extend/theme","docId":"extend/theme"},{"type":"link","label":"Views and Blade","href":"/de/extend/views","docId":"extend/views"},{"type":"link","label":"GitHub Actions (Workflows)","href":"/de/extend/github-actions","docId":"extend/github-actions"}],"collapsed":false},{"type":"category","label":"Advanced Guides","collapsible":false,"className":"menu__refs-category","items":[{"type":"link","label":"API Throttling","href":"/de/extend/api-throttling","docId":"extend/api-throttling"},{"type":"link","label":"Extension Assets","href":"/de/extend/assets","docId":"extend/assets"},{"type":"link","label":"Konsole","href":"/de/extend/console","docId":"extend/console"},{"type":"link","label":"Extending Extensions","href":"/de/extend/extending-extensions","docId":"extend/extending-extensions"},{"type":"link","label":"Extensibility","href":"/de/extend/extensibility","docId":"extend/extensibility"},{"type":"link","label":"Filesystem","href":"/de/extend/filesystem","docId":"extend/filesystem"},{"type":"link","label":"Formatting","href":"/de/extend/formatting","docId":"extend/formatting"},{"type":"link","label":"Mail Drivers","href":"/de/extend/mail","docId":"extend/mail"},{"type":"link","label":"Middleware","href":"/de/extend/middleware","docId":"extend/middleware"},{"type":"link","label":"Model Visibility","href":"/de/extend/model-visibility","docId":"extend/model-visibility"},{"type":"link","label":"Model Slugging","href":"/de/extend/slugging","docId":"extend/slugging"},{"type":"link","label":"Notifications","href":"/de/extend/notifications","docId":"extend/notifications"},{"type":"link","label":"Post Types","href":"/de/extend/post-types","docId":"extend/post-types"},{"type":"link","label":"Searching and Filtering","href":"/de/extend/search","docId":"extend/search"},{"type":"link","label":"Service Provider","href":"/de/extend/service-provider","docId":"extend/service-provider"}],"collapsed":false},{"type":"category","label":"Update Guides","collapsible":false,"className":"menu__advanced-category","items":[{"type":"link","label":"Updating For 1.x","href":"/de/extend/update-1_x","docId":"extend/update-1_x"},{"type":"link","label":"Updating For 1.0","href":"/de/extend/update-1_0","docId":"extend/update-1_0"},{"type":"link","label":"Updating For Beta 16","href":"/de/extend/update-b16","docId":"extend/update-b16"},{"type":"link","label":"Updating For Beta 15","href":"/de/extend/update-b15","docId":"extend/update-b15"},{"type":"link","label":"Updating For Beta 14","href":"/de/extend/update-b14","docId":"extend/update-b14"},{"type":"link","label":"Updating For Beta 13","href":"/de/extend/update-b13","docId":"extend/update-b13"},{"type":"link","label":"Updating For Beta 12","href":"/de/extend/update-b12","docId":"extend/update-b12"},{"type":"link","label":"Updating For Beta 10","href":"/de/extend/update-b10","docId":"extend/update-b10"},{"type":"link","label":"Updating For Beta 8","href":"/de/extend/update-b8","docId":"extend/update-b8"}],"collapsed":false}],"internalSidebar":[{"type":"category","label":"Internal Docs","collapsible":false,"items":[{"type":"link","label":"Interne Team Dokumentation","href":"/de/internal","docId":"internal/README"},{"type":"link","label":"PR Merging Policy","href":"/de/internal/merging-policy","docId":"internal/merging-policy"},{"type":"link","label":"Bundled Extensions Policy","href":"/de/internal/bundled-extensions-policy","docId":"internal/bundled-extensions-policy"},{"type":"link","label":"Extension Manager","href":"/de/internal/extension-manager","docId":"internal/extension-manager"}],"collapsed":false}]},"docs":{"admin":{"id":"admin","title":"Admin-Dashboard","description":"Das Flarum Admin Dashboard ist eine benutzerfreundliche Oberfl\xe4che zur Verwaltung deines Forums. Es ist nur f\xfcr Benutzer in der Gruppe \u201eAdmin\u201c verf\xfcgbar. Um auf das Admin-Dashboard zuzugreifen, klicke oben rechts auf dem Bildschirm auf deinen Namen und w\xe4hle Administration aus.","sidebar":"guideSidebar"},"bugs":{"id":"bugs","title":"Fehler melden","description":"Wenn Du eine Sicherheitsl\xfccke in Flarum entdeckst, befolge bitte unsere Sicherheitsrichtlinie, damit wir sie umgehend beheben k\xf6nnen.","sidebar":"guideSidebar"},"code-of-conduct":{"id":"code-of-conduct","title":"Verhaltenskodex","description":"Willkommen in der Flarum-Community!","sidebar":"guideSidebar"},"composer":{"id":"composer","title":"Composer","description":"Flarum uses a program called Composer to manage its dependencies and extensions. You\'ll need to use composer if you want to:","sidebar":"guideSidebar"},"config":{"id":"config","title":"Konfigurationsdatei","description":"Es existiert nur ein Ort, an dem die Flarum-Konfiguration nicht \xfcber das Flarum-Admin-Dashboard (mit Ausnahme der Datenbank) ge\xe4ndert werden kann, und das ist die Datei config.php, die sich im Stammverzeichnis deiner Flarum-Installation befindet.","sidebar":"guideSidebar"},"console":{"id":"console","title":"Konsole","description":"Zus\xe4tzlich zum Admin-Dashboard bietet Flarum mehrere Konsolenbefehle, mit denen du dein Forum \xfcber das Terminal verwalten kannst.","sidebar":"guideSidebar"},"contributing":{"id":"contributing","title":"Hilf Flarum aufzubauen","description":"Interested in contributing to Flarum development? That\'s great! From opening a bug report to creating a pull request: every single one is appreciated and welcome. Flarum wouldn\'t be possible without our community contributions.","sidebar":"guideSidebar"},"contributing-docs-translations":{"id":"contributing-docs-translations","title":"Dokumente und \xdcbersetzung","description":"Dokumentation hinzuf\xfcgen","sidebar":"guideSidebar"},"extend/admin":{"id":"extend/admin","title":"Admin-Dashboard","description":"Beta 15 f\xfchrte ein komplett neu gestaltetes Admin-Panel und eine Frontend-API ein. Es ist jetzt einfacher denn je, deiner Erweiterung Einstellungen oder Berechtigungen hinzuzuf\xfcgen.","sidebar":"extendSidebar"},"extend/api":{"id":"extend/api","title":"API and Data Flow","description":"In the previous article, we learned how Flarum uses models to interact with data. Here, we\'ll learn how to get that data from the database to the JSON-API to the frontend, and all the way back again.","sidebar":"extendSidebar"},"extend/api-throttling":{"id":"extend/api-throttling","title":"API Throttling","description":"Flarum comes with a builtin Flarum\\\\Api\\\\Middleware\\\\ThrottleApi middleware for throttling requests to the API. This runs on every API route, and extensions can add their own custom logic to throttle requests.","sidebar":"extendSidebar"},"extend/assets":{"id":"extend/assets","title":"Extension Assets","description":"Some extensions might want to include assets like images or JSON files in their source code (note that this is not the same as uploads, which would probably require a filesystem disk).","sidebar":"extendSidebar"},"extend/authorization":{"id":"extend/authorization","title":"Authorization","description":"As with any framework, Flarum allows certain actions and content to be restricted to certain users. There are 2 parallel systems for this:","sidebar":"extendSidebar"},"extend/backend-events":{"id":"extend/backend-events","title":"Backend Events","description":"Often, an extension will want to react to some events occuring elsewhere in Flarum. For instance, we might want to increment a counter when a new discussion is posted, send a welcome email when a user logs in for the first time, or add tags to a discussion before saving it to the database. These events are known as domain events, and are broadcasted across the framework through Laravel\'s event system.","sidebar":"extendSidebar"},"extend/cli":{"id":"extend/cli","title":"Flarum CLI","description":"The Flarum development ecosystem is oriented around many small, modules, interacting extensions. This is a very powerful and flexible paradigm, but it also brings the maintenance cost of creating and maintaining all these extensions.","sidebar":"extendSidebar"},"extend/console":{"id":"extend/console","title":"Konsole","description":"Flarum allows extension developers to add custom console commands in addition to the default ones provided by flarum core.","sidebar":"extendSidebar"},"extend/distribution":{"id":"extend/distribution","title":"Distribution","description":"You\'ve written a great extension \u2014\xa0and now you want the whole world to be able to use it. This document will take you through the process of distribution, from setting up a Git repository for your extension, to publishing it on Packagist.","sidebar":"extendSidebar"},"extend/extending-extensions":{"id":"extend/extending-extensions","title":"Extending Extensions","description":"Flarum extensions aren\'t just for adding features to core: extensions can extend other extensions!","sidebar":"extendSidebar"},"extend/extensibility":{"id":"extend/extensibility","title":"Extensibility","description":"In some cases, you might want other extensions to extend your extension.","sidebar":"extendSidebar"},"extend/filesystem":{"id":"extend/filesystem","title":"Filesystem","description":"Flarum core integrates with the filesystem to store and serve assets (like compiled JS/CSS or upload logos/favicons) and avatars.","sidebar":"extendSidebar"},"extend/formatting":{"id":"extend/formatting","title":"Formatting","description":"Flarum uses the powerful s9e TextFormatter library to format posts from plain markup into HTML. You should become familiar with how TextFormatter works before you attempt to extend it.","sidebar":"extendSidebar"},"extend/forms":{"id":"extend/forms","title":"Forms and Requests","description":"In this article, we\'ll go over some frontend tools that are available to us for building and managing forms, as well how to send HTTP requests via Flarum.","sidebar":"extendSidebar"},"extend/frontend":{"id":"extend/frontend","title":"Frontend Development","description":"This page describes how to make changes to Flarum\'s user interface. How to add buttons, marquees, and blinking text. \ud83e\udd29","sidebar":"extendSidebar"},"extend/frontend-pages":{"id":"extend/frontend-pages","title":"Frontend Pages and Resolvers","description":"As explained in the Routes and Content documentation, we can use Mithril\'s routing system to show different components for different routes. Mithril allows you to use any component you like, even a Modal or Alert, but we recommend sticking to component classes that inherit the Page component.","sidebar":"extendSidebar"},"extend/github-actions":{"id":"extend/github-actions","title":"GitHub Actions (Workflows)","description":"In public repos, GitHub Actions allow you to run jobs on every commit and pull request for free. These processes can be automated tests, builds, code inspections ..etc. You can find more information about GitHub Actions here.","sidebar":"extendSidebar"},"extend/i18n":{"id":"extend/i18n","title":"Internationalization","description":"Flarum features a powerful translation system (based on Symfony\'s translator and ICU MessageFormat) that allows the interface to display information in virtually any language. You should consider taking advantage of Flarum\'s translator as you develop your extension, even if you have no intention of using it in more than a single language.","sidebar":"extendSidebar"},"extend/interactive-components":{"id":"extend/interactive-components","title":"Interactive Components","description":"Often, you\'ll want to trigger interactive components in addition to whatever content/animations you have on a given page. Depending on the nature of your extension, you may want to define custom interactive elements or reuse or extend existing ones.","sidebar":"extendSidebar"},"extend/language-packs":{"id":"extend/language-packs","title":"Translating Flarum","description":"This documentation covers the technical structure of language packs. Read this article for information on how to start / contribute to a Flarum language pack.","sidebar":"extendSidebar"},"extend/mail":{"id":"extend/mail","title":"Mail Drivers","description":"In addition to the default drivers in core, Flarum allows new mail drivers to be added through extenders. To create your own mail driver, you\'ll need to create a class implementing \\\\Flarum\\\\Mail\\\\DriverInterface. Flarum actually takes care of the frontend for providing email settings: just declare which settings you need, and any default values, in availableSettings.","sidebar":"extendSidebar"},"extend/middleware":{"id":"extend/middleware","title":"Middleware","description":"Middleware is a nifty way to wrap the handling of HTTP requests in Flarum. This can allow you to modify responses, add your own checks to the request, and much more. The possibilities are endless!","sidebar":"extendSidebar"},"extend/model-visibility":{"id":"extend/model-visibility","title":"Model Visibility","description":"This article concerns authorization, and uses some concepts from the authorization system. You should familiarize yourself with that first.","sidebar":"extendSidebar"},"extend/models":{"id":"extend/models","title":"Models and Migrations","description":"At the foundation, any forum revolves around data: users provide discussions, posts, profile information, etc. Our job as forum developers is to provide a great experience for creating, reading, updating, and deleting this data. This article will discuss how Flarum stores and access data. In the next article, we\'ll follow up on this by explaining how data flows through the API.","sidebar":"extendSidebar"},"extend/notifications":{"id":"extend/notifications","title":"Notifications","description":"Flarum includes a powerful notification system to alert users to new activity.","sidebar":"extendSidebar"},"extend/permissions":{"id":"extend/permissions","title":"Groups and Permissions","description":"In addition to labeling roles, Flarum\'s group system is a way for permissions to be applied to segments of users.","sidebar":"extendSidebar"},"extend/post-types":{"id":"extend/post-types","title":"Post Types","description":"","sidebar":"extendSidebar"},"extend/README":{"id":"extend/README","title":"README","description":"- - -","sidebar":"extendSidebar"},"extend/routes":{"id":"extend/routes","title":"Routes and Content","description":"A fundamental part of extending Flarum is adding routes \u2014\xa0both to expose new resources in the JSON-API, and to add new pages to the frontend.","sidebar":"extendSidebar"},"extend/search":{"id":"extend/search","title":"Searching and Filtering","description":"Flarum treats searching and filtering as parallel but distinct processes. Which process is used to handle a request to a List API endpoint depends on the query parameters:","sidebar":"extendSidebar"},"extend/service-provider":{"id":"extend/service-provider","title":"Service Provider","description":"As noted throughout this documentation, Flarum uses Laravel\'s service container (or IoC container) for dependency injection. Service Providers allow low-level configuration and modification of the Flarum backend. The most common use case for service providers is to create, modify, or replace container bindings. That being said, service providers allow you full access to run whatever logic you need during application boot with access to the container.","sidebar":"extendSidebar"},"extend/settings":{"id":"extend/settings","title":"Settings","description":"At some point while making an extension, you might want to read some of the forum\'s settings or store certain settings specific to your extension. Thankfully, Flarum makes this very easy.","sidebar":"extendSidebar"},"extend/slugging":{"id":"extend/slugging","title":"Model Slugging","description":"","sidebar":"extendSidebar"},"extend/start":{"id":"extend/start","title":"Getting Started","description":"Want to build a Flarum extension? You\'ve come to the right place! This document will take you through some essential concepts, after which you\'ll build your first Flarum extension from scratch.","sidebar":"extendSidebar"},"extend/static-code-analysis":{"id":"extend/static-code-analysis","title":"Static Code Analysis","description":"Static code analysis is the process of analyzing the source code against a set of rules to find bugs, code smells, and security vulnerabilities. This is a great way to improve the quality of your code and to find potential issues before they are deployed to production. An example is validating the typings of a function to ensure that the function is called with the correct arguments.","sidebar":"extendSidebar"},"extend/testing":{"id":"extend/testing","title":"Testing","description":"Automated testing ensures that your extension performs as you expect it to, helps avoid introducing new bugs or regressions, and saves time on manual testing. Flarum currently provides tooling for automated backend unit and integration tests, and we plan to release support for frontend unit testing and E2E testing in the future.","sidebar":"extendSidebar"},"extend/theme":{"id":"extend/theme","title":"Themes","description":"Flarum \\"themes\\" are just extensions. Typically, you\'ll want to use the Frontend extender to register custom Less and JS. Of course, you can use other extenders too: for example, you might want to support settings to allow configuring your theme.","sidebar":"extendSidebar"},"extend/update-1_0":{"id":"extend/update-1_0","title":"Updating For 1.0","description":"Flarum version 1.0 is the long-awaited stable release! This release brings a number of refactors, cleanup, and small improvements that should make your Flarum experience just a bit better!","sidebar":"extendSidebar"},"extend/update-1_x":{"id":"extend/update-1_x","title":"Updating For 1.x","description":"If you need help applying these changes or using new features, please start a discussion on the community forum or Discord chat.","sidebar":"extendSidebar"},"extend/update-b10":{"id":"extend/update-b10","title":"Updating For Beta 10","description":"Beta 10 further solidifies the core architecture, offering new extenders as a stable, use-case-driven API for extending Flarum\'s core. A few small changes may necessitate updates to your extensions to make them compatible with Beta 10. These are detailed below.","sidebar":"extendSidebar"},"extend/update-b12":{"id":"extend/update-b12","title":"Updating For Beta 12","description":"Beta 12 packs several new features for extension developers, but also continues our cleanup efforts which results in a few changes, so please read this guide carefully to find out whether your extensions are affected. We invested extra effort to introduce new functionality in a backward-compatible manner or first deprecate functionality before it will be removed in the next release, in line with our versioning recommendations.","sidebar":"extendSidebar"},"extend/update-b13":{"id":"extend/update-b13","title":"Updating For Beta 13","description":"Beta 13 ships with several new extenders to simplify building and maintaining extensions. We do our best to create backward compatibility changes. We recommend changing to new Extenders as soon as they are available.","sidebar":"extendSidebar"},"extend/update-b14":{"id":"extend/update-b14","title":"Updating For Beta 14","description":"This release brings a large chunk of breaking changes - hopefully the last chunk of this size before our stable release. In order to prepare the codebase for the upcoming stable release, we decided it was time to modernize / upgrade / exchange some of the underlying JavaScript libraries that are used in the frontend. Due to the nature and size of these upgrades, we have to pass on some of the breaking changes to you, our extension developers.","sidebar":"extendSidebar"},"extend/update-b15":{"id":"extend/update-b15","title":"Updating For Beta 15","description":"Beta 15 features multiple new extenders, a total redesign of the admin dashboard, and several other interesting new features for extensions. As before, we have done our best to provide backwards compatibility layers, and we recommend switching away from deprecated systems as soon as possible to make your extensions more stable.","sidebar":"extendSidebar"},"extend/update-b16":{"id":"extend/update-b16","title":"Updating For Beta 16","description":"Beta 16 finalizes the PHP extender API, introduces a testing library and JS typings, switches to using namespaces for JS imports, increases extension dependency robustness, and allows overriding routes, among other features.","sidebar":"extendSidebar"},"extend/update-b8":{"id":"extend/update-b8","title":"Updating For Beta 8","description":"All extensions will need to be refactored in order to work with beta 8. Here are the main things you will need to do in order to make your extension compatible.","sidebar":"extendSidebar"},"extend/views":{"id":"extend/views","title":"Views and Blade","description":"Although the Flarum UI you know and love is powered by our Mithril frontend, server-side generated templates are still used throughout Flarum. Most notably, the HTML skeleton of the forum, which includes various SEO meta tags, as well as the no-js view of the forum, is implemented through the Views and Blade systems.","sidebar":"extendSidebar"},"extenders":{"id":"extenders","title":"Lokale Extender","description":"Wenn du Anpassungen an deiner Seite vornehmen m\xf6chtest, ohne eine ganze Erweiterung zu erstellen, kannst du dies mit lokalen Extendern tun. Jede Flarum-Installation wird mit einer extend.php-Datei geliefert, in der du Extender-Instanzen hinzuf\xfcgen kannst, genau wie bei einer vollst\xe4ndigen Erweiterung.","sidebar":"guideSidebar"},"extensions":{"id":"extensions","title":"Erweiterungen","description":"Flarum ist minimalistisch, aber auch sehr erweiterbar. Tats\xe4chlich sind die meisten Funktionen, die mit Flarum geliefert werden, tats\xe4chlich Erweiterungen!","sidebar":"guideSidebar"},"faq":{"id":"faq","title":"FAQ","description":"Ist Flarum stabil?","sidebar":"guideSidebar"},"install":{"id":"install","title":"Installation","description":"F\xfchle Dich frei, Flarum in einem unserer Demonstrationsforen auszuprobieren. Or set up your own forum in seconds at Free Flarum, a free community service not affiliated with the Flarum team.","sidebar":"guideSidebar"},"internal/bundled-extensions-policy":{"id":"internal/bundled-extensions-policy","title":"Bundled Extensions Policy","description":"This document is to assist in deciding what core features should be bundled or maintained by the Flarum project team.","sidebar":"internalSidebar"},"internal/extension-manager":{"id":"internal/extension-manager","title":"Extension Manager","description":"This contains an explanation of how the extension manager works and what it has to offer.","sidebar":"internalSidebar"},"internal/merging-policy":{"id":"internal/merging-policy","title":"PR Merging Policy","description":"Technical contributions to the Flarum source code go through a review process. Over the years we have tuned this process based on our experiences, our targeted development speed and availability.","sidebar":"internalSidebar"},"internal/README":{"id":"internal/README","title":"Interne Team Dokumentation","description":"Dies ist ein neuer Dokumentationsbereich, in dem wir einige Dokumente ver\xf6ffentlichen werden, die intern vom Flarum-Team verwendet werden. Wir starten diesen Abschnitt, um unserer Community Transparenz dar\xfcber zu verschaffen, wie Flarum betrieben wird, und um denjenigen zu helfen, die zu Flarum beitragen m\xf6chten.","sidebar":"internalSidebar"},"languages":{"id":"languages","title":"Sprachen","description":"Es ist ganz einfach, deiner Flarum-Basisinstallation eine neue Sprache hinzuzuf\xfcgen. Befolgen einfach die nachstehenden Anweisungen, um das Sprachpaket deiner Wahl herunterzuladen und zu installieren.","sidebar":"guideSidebar"},"mail":{"id":"mail","title":"E-Mail-Konfiguration","description":"Jede Community muss E-Mails senden, um die E-Mail-Verifizierung, das Zur\xfccksetzen von Kennw\xf6rtern, Benachrichtigungen und andere Mitteilungen an Benutzer zu erm\xf6glichen. Das Konfigurieren deines Forums zum Senden von E-Mails sollte einer deiner ersten Schritte als Administrator sein: Eine falsche Konfiguration f\xfchrt zu Fehlern, wenn Benutzer versuchen, sich zu registrieren.","sidebar":"guideSidebar"},"README":{"id":"README","title":"README","description":"- - -","sidebar":"guideSidebar"},"releases":{"id":"releases","title":"Versionshinweise","description":"\x3c!--","sidebar":"guideSidebar"},"rest-api":{"id":"rest-api","title":"Consuming the REST API","description":"Flarum exposes a REST API which is used by the single page application but also available for external scripts.","sidebar":"guideSidebar"},"scheduler":{"id":"scheduler","title":"Scheduler","description":"The Flarum scheduler allows extensions to automate certain tasks effortlessly. In this guide we will see how to set it up. We won\'t go into the details of cron itself, but if you want to read more about it, I suggest you take a look at this Wikipedia article on cron.","sidebar":"guideSidebar"},"themes":{"id":"themes","title":"Design","description":"Obwohl wir hart daran gearbeitet haben, Flarum so sch\xf6n wie m\xf6glich zu machen, wird wahrscheinlich jede Community einige Optimierungen/Modifikationen vornehmen wollen, um sie ihrem gew\xfcnschten Stil anzupassen.","sidebar":"guideSidebar"},"troubleshoot":{"id":"troubleshoot","title":"Problembehandlung","description":"If Flarum isn\'t installing or working as expected, the first thing you should do is check again whether your environment meets the system requirements. If you\'re missing something that Flarum needs to run, you\'ll need to remedy that first.","sidebar":"guideSidebar"},"update":{"id":"update","title":"Updating","description":"From the Admin Dashboard","sidebar":"guideSidebar"}}}')}}]);